class TestAPIEndpoints:
    """Verify the FastAPI app has expected routes."""

    def test_bmc_webhook_handler_app_exists(self):
        from bmc_webhook_handler import app
        assert app is not None
        assert hasattr(app, 'routes')

    def test_bmc_webhook_handler_has_routes(self):
        from bmc_webhook_handler import app
        routes = [app.routes[i].path for i in range(len(app.routes)) if hasattr(app.routes[i], 'path')]
        assert len(routes) > 0, 'App should have at least one route'

    def test_bmc_webhook_handler_has_health_endpoint(self):
        from bmc_webhook_handler import app
        paths = [r.path for r in app.routes if hasattr(r, 'path')]
        health_paths = [p for p in paths if 'health' in p.lower()]
        assert len(health_paths) > 0, "API should have a /health endpoint"

    def test_bmc_webhook_handler_known_routes_registered(self):
        from bmc_webhook_handler import app
        registered = [r.path for r in app.routes if hasattr(r, 'path')]
        known_routes = ['/webhooks/bmc', '/webhooks/bmc/recent', '/webhooks/bmc/stats']
        for route in known_routes:
            assert route in registered, f"Expected route {route} not found"


class TestBMCConfig:
    """Verify BMC configuration is properly structured."""

    def test_tier_map_has_all_tiers(self):
        from bmc_config import TIER_MAP
        assert 'Candlelight Circle' in TIER_MAP
        assert 'Moonlit Coven' in TIER_MAP
        assert 'High Priestess Circle' in TIER_MAP

    def test_tier_levels_consistent(self):
        from premium_content import TIER_LEVELS, TIER_CONTENT
        for tier in TIER_LEVELS:
            assert tier in TIER_CONTENT, f'Tier {tier} missing from TIER_CONTENT'

    def test_tier_content_has_required_keys(self):
        from premium_content import TIER_CONTENT
        required_keys = ["spell_difficulty", "amplify", "monthly_rituals", "knowledge_access"]
        for tier_name, tier_data in TIER_CONTENT.items():
            for key in required_keys:
                assert key in tier_data, f'{key} missing from {tier_name}'

